import numpy as npimport pandas as pdfrom sklearn.model_selection import train_test_splitfrom sklearn.impute import KNNImputer, SimpleImputerfrom sklearn.linear_model import LogisticRegressionfrom sklearn.metrics import accuracy_score# Load selected columns from the datasetdf = pd.read_csv('train.csv')[['Age', 'Pclass', 'Fare', 'Survived']]print(df.head())# Check missing value percentagesprint(df.isnull().mean() * 100)# Separate features and targetX = df.drop(columns=['Survived'])y = df['Survived']# Split into training and testing setsX_train, X_test, y_train, y_test = train_test_split(    X, y, test_size=0.2, random_state=2)print(X_train.head())# Apply KNN Imputerknn = KNNImputer(n_neighbors=3, weights='distance')X_train_trf = knn.fit_transform(X_train)X_test_trf = knn.transform(X_test)# Train Logistic Regression modellr = LogisticRegression(max_iter=1000)lr.fit(X_train_trf, y_train)# Predict and evaluatey_pred = lr.predict(X_test_trf)print(accuracy_score(y_test, y_pred))# Comparison with Simple Imputer (mean strategy)si = SimpleImputer()X_train_trf2 = si.fit_transform(X_train)X_test_trf2 = si.transform(X_test)lr = LogisticRegression(max_iter=1000)lr.fit(X_train_trf2, y_train)y_pred2 = lr.predict(X_test_trf2)print(accuracy_score(y_test, y_pred2))